record_types.code:
type Format_Spec is record
   Alignment : Alignment_Type := Default;
   Fill_Char : Character := ' ';
   Width         : Natural := 0;
   Precision     : Natural := 0;
   Has_Precision : Boolean := False;
   Type_Char : Character := ' ';
   Show_Sign : Boolean := False;
   Alt_Form  : Boolean := False;
   Zero_Pad  : Boolean := False;
end record;

